    40  void EditorScript::add_root_node(Node *p_node) {
    41          if (!EditorNode::get_singleton()) {
    42                  EditorNode::add_io_error("EditorScript::add_root_node: " + TTR("Write your logic in the _run() method."));
    43                  return;
    44          }
    45
    46          if (EditorNode::get_singleton()->get_edited_scene()) {
    47                  EditorNode::add_io_error("EditorScript::add_root_node: " + TTR("The current scene already has a root node."));
    48                  return;
    49          }
    50
    51          const String &scene_path = p_node->get_scene_file_path();
    52          if (!scene_path.is_empty()) {
    53                  Ref<PackedScene> scene = ResourceLoader::load(scene_path);
    54                  if (scene.is_valid()) {
    55                          memfree(scene->instantiate(PackedScene::GEN_EDIT_STATE_INSTANCE)); // Ensure node cache.
    56
    57                          p_node->set_scene_inherited_state(scene->get_state());
    58                          p_node->set_scene_file_path(String());
    59                  }
    60          }
    61
    62          EditorNode::get_singleton()->set_edited_scene(p_node);
    63          EditorUndoRedoManager::get_singleton()->set_history_as_unsaved(EditorNode::get_editor_data().get_current_edited_scene_history_id());
    64          EditorSceneTabs::get_singleton()->update_scene_tabs();
    65  }
