    68          if (!EditorNode::get_singleton()) {
    69                  EditorNode::add_io_error("EditorScript::get_scene: " + TTR("Write your logic in the _run() method."));
    70                  return nullptr;
    71          }
    72
    73          return EditorNode::get_singleton()->get_edited_scene();
    74  }
